import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { MatButtonModule } from '@angular/material/button';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatIconModule } from '@angular/material/icon';
import { MatSnackBar } from '@angular/material/snack-bar';
import { TransactionService } from '../../../core/services/transaction.service';
import { Account } from '../../../core/models/account.model';

@Component({
  selector: 'app-transaction-form',
  standalone: true,
  imports: [
    CommonModule, ReactiveFormsModule,
    MatFormFieldModule, MatInputModule, MatSelectModule,
    MatButtonModule, MatProgressSpinnerModule, MatIconModule,
  ],
  templateUrl: './transaction-form.component.html',
})
export class TransactionFormComponent implements OnInit {
  @Input() account!: Account;
  @Input() customerId!: number;
  @Output() transactionRegistered = new EventEmitter<void>();

  form!: FormGroup;
  loading = false;

  constructor(
    private fb: FormBuilder,
    private transactionService: TransactionService,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      transactionType: ['DEPOSIT', Validators.required],
      amount: ['', [Validators.required, Validators.min(0.01)]],
      description: ['', Validators.maxLength(255)],
    });
    if (!this.isActive) {
      this.form.disable();
    }
  }

  get isActive(): boolean {
    return this.account.status === 'ACTIVE';
  }

  getError(field: string): string {
    const c = this.form.get(field);
    if (!c?.errors || !c.touched) return '';
    if (c.errors['required']) return 'Campo obligatorio';
    if (c.errors['min']) return 'Mínimo $0.01';
    if (c.errors['maxlength']) return 'Máximo 255 caracteres';
    return 'Valor no válido';
  }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.loading = true;
    const { transactionType, amount, description } = this.form.value;
    this.transactionService
      .register(this.account.id, {
        transactionType,
        amount: parseFloat(amount),
        description: description || undefined,
      })
      .subscribe({
        next: (res) => {
          this.snackBar.open(res.message, 'Cerrar', { duration: 3000 });
          this.loading = false;
          this.form.reset({ transactionType: 'DEPOSIT', amount: '', description: '' });
          this.transactionRegistered.emit();
        },
        error: (err: Error) => {
          this.loading = false;
          this.snackBar.open(err.message, 'Cerrar', { duration: 5000, panelClass: 'snack-error' });
        },
      });
  }
}
<div class="transaction-form">
  @if (!isActive) {
    <p class="inactive-msg">
      <mat-icon>warning</mat-icon>
      Esta cuenta está inactiva. No se pueden registrar transacciones.
    </p>
  }
  <form [formGroup]="form" (ngSubmit)="onSubmit()">
    <div class="form-row">
      <mat-form-field appearance="outline">
        <mat-label>Tipo</mat-label>
        <mat-select formControlName="transactionType">
          <mat-option value="DEPOSIT">Consignación</mat-option>
          <mat-option value="WITHDRAWAL">Retiro</mat-option>
        </mat-select>
        <mat-error>{{ getError('transactionType') }}</mat-error>
      </mat-form-field>

      <mat-form-field appearance="outline">
        <mat-label>Monto *</mat-label>
        <input matInput type="number" step="0.01" min="0.01"
               formControlName="amount" placeholder="0.00">
        <mat-error>{{ getError('amount') }}</mat-error>
      </mat-form-field>
    </div>

    <mat-form-field appearance="outline" class="full-width">
      <mat-label>Descripción (opcional)</mat-label>
      <input matInput formControlName="description"
             placeholder="Ej: Pago de nómina">
      <mat-error>{{ getError('description') }}</mat-error>
    </mat-form-field>

    <button mat-flat-button color="primary" type="submit"
            class="submit-btn" [disabled]="loading || !isActive">
      @if (loading) {
        <mat-spinner diameter="16" style="display:inline-block;margin-right:8px"></mat-spinner>
      }
      {{ loading ? 'Procesando...' : 'Registrar transacción' }}
    </button>
  </form>
</div>
